#include <bits/stdc++.h>
using namespace std;

int main(int argc, char** argv) {
    if (argc < 4) return 2;
    ifstream in(argv[1]), out(argv[2]);
    int n;
    if (!(in >> n)) return 2;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        if (!(out >> a[i])) return 1;
    }
    string extra;
    if (out >> extra) return 1;
    vector<int> seen(n + 1, 0);
    for (int x : a) {
        if (x < 1 || x > n) return 1;
        if (seen[x]) return 1;
        seen[x] = 1;
    }
    for (int i = 0; i + 1 < n; ++i) {
        if (abs(a[i] - a[i + 1]) == 1) return 1;
    }
    return 0;
}
